module.render:
const color = args.color || '#fef08a';
const rotate = args.rotate || '-2';
const title = (args.title || '').trim();
const titleColor = (args.titlecolor || '').trim();
// halign = horizontal (left/center/right) via text-align; valign = vertical
// (top/middle/bottom) via flex justify-content (only visible once the note has
// a fixed height in Edit layout).
const h = (args.halign || 'left').toLowerCase();
const v = (args.valign || 'top').toLowerCase();
const justify = v === 'middle' ? 'center' : v === 'bottom' ? 'flex-end' : 'flex-start';
const textAlign = h === 'center' ? 'center' : h === 'right' ? 'right' : 'left';
const contentStr = sections[0] ? sections[0].trim() : '';
// Title is a raw HTML heading (no blank line around it) so markdown leaves it
// alone; the body below renders as markdown.
const titleHtml = title
  ? `<div class="mdp-sticky-title"${titleColor ? ' style="color: ' + titleColor + ';"' : ''}>${title}</div>`
  : '';
return `\n\n<div class="mdp-mod-sticky" style="--sticky-color: ${color}; transform: rotate(${rotate}deg); justify-content: ${justify}; text-align: ${textAlign};">${titleHtml}\n\n${contentStr}\n\n</div>\n\n`;
